from flask import Flask, redirect, url_for, request, session
import requests

app = Flask(__name__)
app.secret_key = 'your_secret_key_here'

CLIENT_ID = 'your_client_id_here'
CLIENT_SECRET = 'your_client_secret_here'
AUTHORIZATION_SERVER_URL = 'https://example.com/oauth/authorize'
TOKEN_ENDPOINT_URL = 'https://example.com/oauth/token'

@app.route('/login')
def login():
    return redirect(url_for('authorization'))

@app.route('/callback')
def callback():
    code = request.args.get('code')
    if not code:
        return 'Error: Authorization failed', 401

    token_response = requests.post(
        TOKEN_ENDPOINT_URL,
        headers={'Content-Type': 'application/x-www-form-urlencoded'},
        data={
            'grant_type': 'authorization_code',
            'code': code,
            'redirect_uri': request.url_root + '/callback',
            'client_id': CLIENT_ID
        }
    )

    if token_response.status_code != 200:
        return 'Error: Failed to obtain access token', 401

    token_data = token_response.json()
    session['access_token'] = token_data.get('access_token')
    return redirect(url_for('protected'))

@app.route('/authorization')
def authorization():
    auth_url = f'{AUTHORIZATION_SERVER_URL}?response_type=code&client_id={CLIENT_ID}&redirect_uri={request.url_root}/callback'
    return redirect(auth_url)

@app.route('/protected')
def protected():
    if 'access_token' not in session:
        return 'Error: Not authorized', 401

    headers = {'Authorization': f'Bearer {session["access_token"]}'}
    response = requests.get('https://example.com/protected-resource', headers=headers)
    return response.text

if __name__ == '__main__':
    app.run(debug=True)